import json
import subprocess
import tempfile
import os

def lambda_handler(event, context):
    code = event['code']

    with tempfile.NamedTemporaryFile(mode='w', suffix='.py', delete=False) as f:
        f.write(code)
        temp_file = f.name

    try:
        result = subprocess.run(
            ['python', temp_file],
            capture_output=True,
            text=True,
            timeout=30
        )
        os.unlink(temp_file)

        return {
            'statusCode': 200,
            'body': json.dumps({
                'stdout': result.stdout,
                'stderr': result.stderr,
                'returncode': result.returncode
            })
        }
    except subprocess.TimeoutExpired:
        os.unlink(temp_file)
        return {
            'statusCode': 408,
            'body': json.dumps({'error': 'Execution timeout'})
        }

import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';

const client = new BedrockAgentRuntimeClient({ region: 'us-east-1' });

interface CodeResponse {
  code: string;
  explanation: string;
  testsPassed: boolean;
}

export async function invokeCodeAgent(
  prompt: string,
  sessionId: string
): Promise<CodeResponse> {
  const command = new InvokeAgentCommand({
    agentId: 'YOUR_AGENT_ID',
    agentAliasId: 'YOUR_AGENT_ALIAS_ID',
    sessionId,
    inputText: prompt,
    enableTrace: true
  });

  const response = await client.send(command);
  let fullOutput = '';

  for await (const chunk of response.completion!) {
    if (chunk.chunk?.bytes) {
      fullOutput += Buffer.from(chunk.chunk.bytes).toString();
    }
  }

  return JSON.parse(fullOutput) as CodeResponse;
}

import boto3

bedrock_agent = boto3.client('bedrock-agent')

# Create knowledge base with code patterns
def create_code_kb():
    response = bedrock_agent.create_knowledge_base(
        name='code-patterns-kb',
        roleArn='arn:aws:iam::ACCOUNT:role/BedrockKBRole',
        knowledgeBaseConfiguration={
            'type': 'VECTOR',
            'vectorKnowledgeBaseConfiguration': {
                'embeddingModelArn': 'arn:aws:bedrock:us-east-1::foundation-model/amazon.titan-embed-text-v1'
            }
        },
        storageConfiguration={
            'type': 'OPENSEARCH_SERVERLESS',
            'opensearchServerlessConfiguration': {
                'collectionArn': 'arn:aws:aoss:us-east-1:ACCOUNT:collection/CODE_COLLECTION',
                'vectorIndexName': 'code_patterns',
                'fieldMapping': {
                    'vectorField': 'embedding',
                    'textField': 'text',
                    'metadataField': 'metadata'
                }
            }
        }
    )
    return response['knowledgeBaseId']

