                "type": "regex_deny",
                "pattern": r"(eval\(|exec\(|__import__\()"
            },
            {
                "name": "no_aws_creds",
                "type": "regex_deny",
                "pattern": r"(AKIA[0-9A-Z]{16}|ASIA[0-9A-Z]{16})"
            }
