import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: 'YOUR_VEX_API_KEY' });

export async function verifyAgentCode(
  agentResponse: string,
  sessionId: string
): Promise<{ isSafe: boolean; code?: string; violations?: string[] }> {
  const result = await vex.verify({
    input: agentResponse,
    policies: [
      'code-safety',
      'syntax-validity',
      'no-credential-leakage',
      'execution-sandboxing',
      {
        name: 'no_system_calls',
        type: 'regex_deny',
        pattern: 'os.system|subprocess.call|Popen'
      },
      {
        name: 'safe_dependencies',
        type: 'dependency_allowlist',
        allowed: ['numpy', 'pandas', 'requests', 'json']
      }
    ],
    context: {
      sessionId,
      riskProfile: 'high',
      useCase: 'code-generation'
    }
  });

  return {
    isSafe: result.isSafe,
    code: result.isSafe ? result.output : undefined,
    violations: result.violations
  };
}

from vex_sdk import Vex

vex = Vex(api_key="YOUR_VEX_API_KEY")

class CodeAgentSession:
    def __init__(self, session_id: str):
        self.session_id = session_id
        self.history = []

    def generate_and_verify(self, prompt: str):
        # Agent invocation
        raw_code = invoke_code_agent(prompt, self.session_id)

        # Verify with session context
        verified = vex.verify(
            input=raw_code,
            policies=[
                "code-safety",
                {
                    "name": "session_consistency",
                    "type": "semantic_similarity",
                    "reference": self.history[-1] if self.history else None,
                    "threshold": 0.8
                }
            ],
            context={
                "session_id": self.session_id,
                "iteration": len(self.history),
                "previous_code": self.history[-1] if self.history else None
            }
        )

        if verified.is_safe:
            self.history.append(verified.output)

        return verified
